//! Spec-compliance tests: Numbering Resolution Chain (ISO 29500-1 §17.9)
//!
//! These tests verify the numbering resolution chain (abstract -> concrete -> override),
//! level formatting semantics, and numbering interaction rules.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/numbering-audit/create_docs.py`.

use stemma::{BlockNode, CanonDoc, TrackedBlock};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/numbering-audit";

// ── helpers ──────────────────────────────────────────────────────────────

/// Extract the numbering prefix from each paragraph.
///
/// For structurally numbered paragraphs (numPr -> numbering engine), the prefix
/// is extracted from synthesized_text in NumberingInfo.
/// For manually typed enumerators, it comes from literal_prefix.
/// Non-numbered paragraphs produce None.
fn numbering_prefixes(doc: &CanonDoc) -> Vec<Option<String>> {
    let mut prefixes = Vec::new();
    collect_prefixes_tracked(&doc.blocks, &mut prefixes);
    prefixes
}

fn collect_prefixes_tracked(blocks: &[TrackedBlock], out: &mut Vec<Option<String>>) {
    for tracked in blocks {
        match &tracked.block {
            BlockNode::Paragraph(p) => {
                out.push(extract_prefix(p));
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_prefixes_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

fn collect_prefixes_bare(blocks: &[BlockNode], out: &mut Vec<Option<String>>) {
    for block in blocks {
        match block {
            BlockNode::Paragraph(p) => {
                out.push(extract_prefix(p));
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_prefixes_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

/// Extract the numbering prefix from a paragraph.
///
/// Prefers NumberingInfo.synthesized_text; falls back to literal_prefix;
/// falls back to splitting rendered_text on tab.
fn extract_prefix(p: &stemma::ParagraphNode) -> Option<String> {
    // Synthesized numbering text from the numbering engine
    if let Some(ref num_info) = p.numbering
        && !num_info.synthesized_text.is_empty()
    {
        return Some(num_info.synthesized_text.clone());
    }
    if let Some(ref lp) = p.literal_prefix {
        return Some(lp.clone());
    }
    // For synthesized numbering, rendered_text is "prefix\tbody text"
    if let Some(ref rt) = p.rendered_text
        && let Some(idx) = rt.find('\t')
    {
        let prefix = rt[..idx].to_string();
        if !prefix.is_empty() {
            return Some(prefix);
        }
    }
    None
}

// ── 1. start default of 0 (ISO 29500-1 §17.9.25) ───────────────────────

/// ISO 29500-1 §17.9.25: "If [the start] element is omitted, then the
/// starting value shall be zero (0)."
///
/// When w:start is absent from a level definition, the first numbered
/// paragraph should display "0.", the second "1.", etc.
///
#[test]
fn spec_start_default_zero_when_omitted() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "start-default-zero");

    let prefixes = numbering_prefixes(&doc);
    let numbered: Vec<&str> = prefixes.iter().filter_map(|p| p.as_deref()).collect();

    assert!(
        numbered.len() >= 4,
        "should have at least 4 numbered paragraphs, got {}: {:?}",
        numbered.len(),
        numbered
    );

    // Per §17.9.25: omitted start defaults to 0
    assert_eq!(
        numbered[0], "0.",
        "first item with omitted w:start should be '0.' per §17.9.25 (start defaults to 0), \
         got '{}'. The implementation likely defaults to 1 instead of the spec-mandated 0.",
        numbered[0]
    );
    assert_eq!(
        numbered[1], "1.",
        "second item should be '1.', got '{}'",
        numbered[1]
    );
    assert_eq!(
        numbered[2], "2.",
        "third item should be '2.', got '{}'",
        numbered[2]
    );

    // Control: level 1 has explicit start=1, so first sub-item is "a)"
    assert_eq!(
        numbered[3], "a)",
        "sub-item with explicit start=1 should be 'a)', got '{}'",
        numbered[3]
    );
}

// ── 2. suff (suffix) types (ISO 29500-1 §17.9.28) ─────────────────────

/// ISO 29500-1 §17.9.28: The suff element controls what character appears
/// between the numbering text and the paragraph body.
///
/// Values: "tab" (default), "space", "nothing".
///
/// This test verifies that the suffix type controls the separator between
/// numbering text and paragraph body in rendered_text.
#[test]
fn spec_suff_element_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "suffix-types");

    let paras = common::all_paragraphs(&doc);

    // All 6 paragraphs should have numbering info
    let numbered_paras: Vec<_> = paras.iter().filter(|p| p.numbering.is_some()).collect();
    assert!(
        numbered_paras.len() >= 6,
        "should have at least 6 numbered paragraphs, got {}",
        numbered_paras.len()
    );

    // Tab suffix (numId=1): rendered_text should use tab separator
    let tab_para = &numbered_paras[0];
    let tab_rendered = tab_para
        .rendered_text
        .as_ref()
        .expect("tab-suffix paragraph should have rendered_text");
    assert!(
        tab_rendered.contains('\t'),
        "tab suffix: rendered_text should contain tab, got: '{tab_rendered}'"
    );

    // Space suffix (numId=2): rendered_text should use space separator, not tab
    let space_para = &numbered_paras[2];
    let space_rendered = space_para
        .rendered_text
        .as_ref()
        .expect("space-suffix paragraph should have rendered_text");
    assert!(
        !space_rendered.contains('\t'),
        "space suffix per §17.9.28: rendered_text should use space separator, not tab. \
         Got '{space_rendered}'. The suff element is not parsed — implementation always uses tab."
    );

    // Nothing suffix (numId=3): rendered_text should have no separator
    let nothing_para = &numbered_paras[4];
    let nothing_rendered = nothing_para
        .rendered_text
        .as_ref()
        .expect("nothing-suffix paragraph should have rendered_text");
    // The rendered text should be "1.Nothing suffix first" (no tab, no space)
    let prefix = nothing_para
        .numbering
        .as_ref()
        .unwrap()
        .synthesized_text
        .clone();
    let expected_start = format!("{prefix}Nothing");
    assert!(
        nothing_rendered.starts_with(&expected_start),
        "nothing suffix per §17.9.28: rendered_text should have no separator between \
         number and body text. Expected to start with '{expected_start}', got '{nothing_rendered}'. \
         The suff element is not parsed — implementation always uses tab."
    );
}

// ── 3. lvlRestart specific level (ISO 29500-1 §17.9.10) ────────────────

/// ISO 29500-1 §17.9.10: lvlRestart val="1" means "restart this level only
/// when level 0 (1-based index 1 = 0-indexed level 0) or any earlier level
/// is used."
///
/// Level 2 has lvlRestart=1. When level 1 appears after level 2, level 2
/// should NOT restart. Only when level 0 appears should level 2 restart.
///
/// Sequence: 1. / a) / b) / i) / ii) / c) / iii) / iv) / 2. / a) / i)
///
/// The key assertion: after "c)" at level 1, level 2 should continue at
/// "iii)", not restart to "i)".
#[test]
fn spec_lvl_restart_specific_level() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "lvl-restart-specific");

    let prefixes = numbering_prefixes(&doc);
    let numbered: Vec<&str> = prefixes.iter().filter_map(|p| p.as_deref()).collect();

    assert!(
        numbered.len() >= 11,
        "should have at least 11 numbered paragraphs, got {}: {:?}",
        numbered.len(),
        numbered
    );

    // Group 1: 1. / a) / b) / i) / ii)
    assert_eq!(
        numbered[0], "1.",
        "level 0 first should be '1.', got '{}'",
        numbered[0]
    );
    assert_eq!(
        numbered[1], "a)",
        "level 1 first should be 'a)', got '{}'",
        numbered[1]
    );
    assert_eq!(
        numbered[2], "b)",
        "level 1 second should be 'b)', got '{}'",
        numbered[2]
    );
    assert_eq!(
        numbered[3], "i)",
        "level 2 first should be 'i)', got '{}'",
        numbered[3]
    );
    assert_eq!(
        numbered[4], "ii)",
        "level 2 second should be 'ii)', got '{}'",
        numbered[4]
    );

    // Back to level 1: level 2 should NOT restart (lvlRestart=1 means only level 0 triggers)
    assert_eq!(
        numbered[5], "c)",
        "level 1 third should be 'c)', got '{}'",
        numbered[5]
    );

    // Level 2 should CONTINUE at iii), not restart to i)
    // Per §17.9.10: lvlRestart=1 means restart when level 0 (or earlier) is used.
    // Level 1 was used, but that's not level 0, so no restart.
    assert_eq!(
        numbered[6], "iii)",
        "level 2 should continue at 'iii)' (not restart to 'i)') because lvlRestart=1 \
         means only level 0 triggers restart, not level 1. Got '{}'.",
        numbered[6]
    );
    assert_eq!(
        numbered[7], "iv)",
        "level 2 should continue at 'iv)', got '{}'",
        numbered[7]
    );

    // Back to level 0: NOW level 2 should restart
    assert_eq!(
        numbered[8], "2.",
        "level 0 second should be '2.', got '{}'",
        numbered[8]
    );
    assert_eq!(
        numbered[9], "a)",
        "level 1 should restart after level 0, got '{}'",
        numbered[9]
    );
    assert_eq!(
        numbered[10], "i)",
        "level 2 should restart to 'i)' after level 0 was used, got '{}'",
        numbered[10]
    );
}

// ── 4. numStyleLink chain (ISO 29500-1 §17.9.21, §17.9.27) ─────────────

/// ISO 29500-1 §17.9.21: When an abstractNum has a numStyleLink, it
/// references a numbering style whose numPr points to the actual numbering
/// definition. The chain must be followed to resolve level definitions.
///
/// abstractNum 0 has numStyleLink="OutlineNumbering" (no levels).
/// Style "OutlineNumbering" (type=numbering) has numPr -> numId=2.
/// numId=2 -> abstractNum 1 which has the actual level definitions.
///
/// Paragraphs using numId=1 should follow the chain and get numbering.
///
#[test]
fn spec_num_style_link_chain() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "num-style-link");

    let prefixes = numbering_prefixes(&doc);
    let numbered: Vec<&str> = prefixes.iter().filter_map(|p| p.as_deref()).collect();

    assert!(
        numbered.len() >= 3,
        "should have at least 3 numbered paragraphs (via numStyleLink chain), got {}: {:?}. \
         If 0 numbered paragraphs were found, the numStyleLink chain is not followed — \
         abstractNum 0 has no levels and numStyleLink='OutlineNumbering' is ignored.",
        numbered.len(),
        numbered
    );

    // The chain should resolve to abstractNum 1's levels
    assert_eq!(
        numbered[0], "1.",
        "first paragraph via numStyleLink should be '1.', got '{}'",
        numbered[0]
    );
    assert_eq!(
        numbered[1], "2.",
        "second paragraph via numStyleLink should be '2.', got '{}'",
        numbered[1]
    );
    assert_eq!(
        numbered[2], "a)",
        "third paragraph (level 1) via numStyleLink should be 'a)', got '{}'",
        numbered[2]
    );
}

// ── 5. lvlOverride with both startOverride AND level (§17.9.8, §17.9.26) ─

/// ISO 29500-1 §17.9.8 + §17.9.26: A lvlOverride can contain BOTH a full
/// level replacement and a startOverride. The level replacement provides
/// the formatting (numFmt, lvlText), the startOverride provides the start.
///
/// numId=2 has lvlOverride with:
///   - startOverride val="10"
///   - full lvl replacement: upperLetter format, lvlText="(%1)"
///
/// Expected: "(J)", "(K)" — upperLetter starting at 10.
///
#[test]
fn spec_lvl_override_with_both_start_and_level() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "lvl-override-both");

    let prefixes = numbering_prefixes(&doc);
    let numbered: Vec<&str> = prefixes.iter().filter_map(|p| p.as_deref()).collect();

    assert!(
        numbered.len() >= 4,
        "should have at least 4 numbered paragraphs, got {}: {:?}",
        numbered.len(),
        numbered
    );

    // Control: numId=1 (original abstract definition)
    assert_eq!(
        numbered[0], "1.",
        "control first should be '1.', got '{}'",
        numbered[0]
    );
    assert_eq!(
        numbered[1], "2.",
        "control second should be '2.', got '{}'",
        numbered[1]
    );

    // Override: numId=2 with both startOverride=10 and level replacement (upperLetter)
    // 10th letter is J, so should be "(J)"
    assert_eq!(
        numbered[2], "(J)",
        "first override item should be '(J)' — upperLetter format from level \
         replacement, starting at 10 from startOverride. Got '{}'.",
        numbered[2]
    );
    assert_eq!(
        numbered[3], "(K)",
        "second override item should be '(K)', got '{}'",
        numbered[3]
    );
}

// ── 6. isLgl on current level with non-decimal format (§17.9.4) ─────────

/// ISO 29500-1 §17.9.4: "all levels displayed for a given numbering
/// level's text shall be displayed using the decimal number format,
/// regardless of the actual number format of that level in the list."
///
/// When isLgl is set on level 1 (which has numFmt=lowerLetter), and
/// lvlText is "%1.%2", BOTH %1 and %2 should render as decimal.
///
/// Level 1 itself has lowerLetter format, but isLgl forces it to decimal.
/// Expected: "1.1", "1.2" — NOT "1.a", "1.b".
#[test]
fn spec_is_lgl_forces_current_level_to_decimal() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "is-lgl-current-level");

    let prefixes = numbering_prefixes(&doc);
    let numbered: Vec<&str> = prefixes.iter().filter_map(|p| p.as_deref()).collect();

    assert!(
        numbered.len() >= 3,
        "should have at least 3 numbered paragraphs, got {}: {:?}",
        numbered.len(),
        numbered
    );

    // Level 0: normal decimal
    assert_eq!(
        numbered[0], "1.",
        "level 0 should be '1.', got '{}'",
        numbered[0]
    );

    // Level 1: isLgl forces ALL %N to decimal, including the current level
    assert_eq!(
        numbered[1], "1.1",
        "level 1 with isLgl should be '1.1' (both levels forced to decimal), \
         got '{}'. If this is '1.a', then isLgl is not forcing the current \
         level's own format to decimal.",
        numbered[1]
    );
    assert_eq!(
        numbered[2], "1.2",
        "level 1 continuation with isLgl should be '1.2', got '{}'",
        numbered[2]
    );
}

// ── 7. Multiple lvlOverrides on different levels (§17.9.8) ──────────────

/// ISO 29500-1 §17.9.8: A num can have lvlOverride children on multiple
/// different levels. Each override should independently affect its level.
///
/// numId=2 has:
///   - lvlOverride ilvl=0: startOverride=5
///   - lvlOverride ilvl=1: startOverride=3
///
/// Expected: level 0 starts at 5, level 1 starts at 3 (c is 3rd letter).
#[test]
fn spec_multi_level_override() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "multi-level-override");

    let prefixes = numbering_prefixes(&doc);
    let numbered: Vec<&str> = prefixes.iter().filter_map(|p| p.as_deref()).collect();

    assert!(
        numbered.len() >= 6,
        "should have at least 6 numbered paragraphs, got {}: {:?}",
        numbered.len(),
        numbered
    );

    // Control (numId=1): default start values
    assert_eq!(
        numbered[0], "1.",
        "control level 0 should be '1.', got '{}'",
        numbered[0]
    );
    assert_eq!(
        numbered[1], "a)",
        "control level 1 should be 'a)', got '{}'",
        numbered[1]
    );

    // Override (numId=2): both levels have startOverride
    assert_eq!(
        numbered[2], "5.",
        "override level 0 should start at '5.' (startOverride=5), got '{}'",
        numbered[2]
    );
    assert_eq!(
        numbered[3], "c)",
        "override level 1 should start at 'c)' (startOverride=3), got '{}'",
        numbered[3]
    );
    assert_eq!(
        numbered[4], "d)",
        "override level 1 continuation should be 'd)', got '{}'",
        numbered[4]
    );
    assert_eq!(
        numbered[5], "6.",
        "override level 0 continuation should be '6.', got '{}'",
        numbered[5]
    );
}

// ── 8. isLgl preserves numFmt=none (§17.9.4, MS-OI29500 §17.9.4b) ──────

/// MS-OI29500 §17.9.4b: When isLgl is set, levels with numFmt=none are
/// NOT forced to decimal. The none format produces empty text, and isLgl
/// preserves that.
///
/// Level 0: numFmt=none (produces "")
/// Level 2: isLgl, lvlText="%1.%2.%3"
///
/// Expected for level 2: ".1.1" — %1 is empty (none preserved),
/// %2 and %3 are forced to decimal.
#[test]
fn spec_is_lgl_preserves_none_format() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "is-lgl-none-preserved");

    let prefixes = numbering_prefixes(&doc);
    let numbered: Vec<&str> = prefixes.iter().filter_map(|p| p.as_deref()).collect();

    // Level 0 has numFmt=none, which should produce no visible numbering text.
    // Level 1 has lowerLetter.
    // Level 2 has isLgl with lvlText="%1.%2.%3".
    //
    // For the numbering engine, we need at least level 2 to be synthesized.
    // Level 0 (none) produces empty string from synthesize().
    // Level 1 (lowerLetter) produces "a)".
    // Level 2 (isLgl) should produce ".1.1".

    // Find the level 2 prefix. It might be the last numbered paragraph.
    let level2_prefix = numbered.iter().find(|p| p.contains('.')).expect(
        "should have a level 2 paragraph with isLgl text containing '.'. \
             Got prefixes: {:?}",
    );

    assert_eq!(
        *level2_prefix, ".1.1",
        "level 2 with isLgl should be '.1.1' — %1 is empty (none format preserved \
         per MS-OI29500 §17.9.4b), %2 and %3 forced to decimal. Got '{level2_prefix}'."
    );
}

// ── 9. Unit test: NumberingDefinitions.parse handles suff ────────────────

/// Direct unit test for suff parsing in NumberingDefinitions.
///
/// Verifies that LevelDef.suffix is correctly parsed from w:suff elements,
/// including the default value (Tab) when the element is omitted.
#[test]
fn spec_suff_field_on_level_def() {
    // This test uses the numbering module directly to verify parsing.
    let xml = r#"<?xml version="1.0" encoding="UTF-8"?>
<w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:abstractNum w:abstractNumId="0">
    <w:lvl w:ilvl="0">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:lvlText w:val="%1."/>
      <w:suff w:val="space"/>
    </w:lvl>
    <w:lvl w:ilvl="1">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:lvlText w:val="%2."/>
      <w:suff w:val="nothing"/>
    </w:lvl>
    <w:lvl w:ilvl="2">
      <w:start w:val="1"/>
      <w:numFmt w:val="decimal"/>
      <w:lvlText w:val="%3."/>
    </w:lvl>
  </w:abstractNum>
  <w:num w:numId="1">
    <w:abstractNumId w:val="0"/>
  </w:num>
</w:numbering>"#;

    let defs = stemma::numbering::NumberingDefinitions::parse(xml.as_bytes())
        .expect("should parse numbering XML");

    let level0 = defs.get_level(1, 0).expect("should find level 0");
    let level1 = defs.get_level(1, 1).expect("should find level 1");
    let level2 = defs.get_level(1, 2).expect("should find level 2");

    // Level 0: suff="space"
    // Level 1: suff="nothing"
    // Level 2: suff omitted (defaults to "tab" per §17.9.28)
    //
    // Bug: LevelDef has no suffix field, so we can only check it exists.
    // This test documents the expected API.

    // For now, just verify the levels parse correctly (basic sanity).
    // The real test is whether we can query the suffix from the level.
    assert_eq!(level0.num_fmt, stemma::numbering::NumFormat::Decimal);
    assert_eq!(level1.num_fmt, stemma::numbering::NumFormat::Decimal);
    assert_eq!(level2.num_fmt, stemma::numbering::NumFormat::Decimal);

    assert_eq!(level0.suffix, stemma::numbering::LevelSuffix::Space);
    assert_eq!(level1.suffix, stemma::numbering::LevelSuffix::Nothing);
    assert_eq!(level2.suffix, stemma::numbering::LevelSuffix::Tab); // default per §17.9.28
}

// ── 10. startOverride counter interaction ────────────────────────────────

/// ISO 29500-1 §17.9.26: startOverride resets the counter on first use.
/// Subsequent paragraphs at the same level should continue incrementing
/// from the overridden value.
///
/// This test verifies that when two numId values share the same abstractNum,
/// startOverride on one does not affect the other's counter.
///
/// numId=1: abstract definition, starts at 1 -> "1.", "2."
/// numId=2: same abstract, startOverride=5 -> "5.", "6."
///
/// Then back to numId=1: should it continue at 3? or restart?
/// Per the implementation, switching numId clears that numId's counters.
#[test]
fn spec_start_override_counter_isolation() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "multi-level-override");

    let prefixes = numbering_prefixes(&doc);
    let numbered: Vec<&str> = prefixes.iter().filter_map(|p| p.as_deref()).collect();

    // This test verifies the basic counter isolation between numIds.
    // numId=1's counters and numId=2's counters are independent.
    assert!(numbered.len() >= 4);

    // numId=1: should start at 1
    assert_eq!(numbered[0], "1.", "numId=1 first: '1.'");

    // numId=2: should start at 5 (from startOverride)
    assert_eq!(
        numbered[2], "5.",
        "numId=2 first: startOverride=5 produces '5.'"
    );
}
